    // Round-robin selection of the run queue index.
    let cpu_num = axhal::cpu_num();
    loop {
        let index = RUN_QUEUE_INDEX.fetch_add(1, Ordering::SeqCst) % cpu_num;
        if cpumask.get(index) {
